@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam roundcorner 12

abstract class Duck << (A,#BFEFF2) >> {
  {abstract} +display() : void
  quack() : void
  swim() : void
  fly() : void
}

class WildDuck << (C,#BFE6C6) >> {
  display() : void
}

class PekingDuck << (C,#BFE6C6) >> {
  display() : void
  fly() : void
}

class ToyDuck << (C,#BFE6C6) >> {
  display() : void
  quack() : void
  swim() : void
  fly() : void
}

Duck <|-- WildDuck
Duck <|-- PekingDuck
Duck <|-- ToyDuck

@enduml
